// Фильтр свежих альбомов/синглов с Deezer API за 14 дней
const drops = [];
const now = new Date();
const cutoff = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);

for (const item of $input.all()) {
  const albums = item.json.data || [];
  for (const alb of albums) {
    if (alb.release_date) {
      const relDate = new Date(alb.release_date);
      if (relDate >= cutoff) {
        const recType = (alb.record_type === 'album' || alb.record_type === 'ep') ? 'album' : 'single';
        drops.push({
          json: {
            artist: alb.artist ? alb.artist.name : item.json.artist_name || '',
            title: alb.title,
            type: recType,
            url: `https://open.spotify.com/search/${encodeURIComponent(alb.title)}` 
          }
        });
      }
    }
  }
}
return drops;

const favArtists = new Set();
for (const item of $input.all()) {
  if (item.json.name) {
    favArtists.add(item.json.name.toLowerCase());
  }
}

const drops = [];
const dedup = new Set();

function decodeEntities(encodedString) {
  return encodedString
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

for (const item of $input.all()) {
  const desc = item.json.description || item.json.title || '';
  const clean = decodeEntities(desc.replace(/<[^>]+>/g, '\n'));
  let currentType = 'single';
  for (let line of clean.split('\n')) {
    line = line.trim();
    const lLower = line.toLowerCase();
    if (lLower.includes('альбомы') || lLower.includes('ep')) {
      currentType = 'album';
      continue;
    }
    if (lLower.includes('синглы')) {
      currentType = 'single';
      continue;
    }
    if (lLower.includes('присылайте') || lLower.includes('забыли')) {
      continue;
    }
    if (line.startsWith('•') || line.startsWith('-') || line.startsWith('—') || (line.length > 2 && !isNaN(parseInt(line[0])) && (line[1] === '.' || line[2] === '.'))) {
      const cleaned = line.replace(/^[•—\-*\d.\s]+/, '').trim();
      if (cleaned.includes('—') || cleaned.includes('-')) {
        const parts = cleaned.split(/\s+[—\-]\s+/);
        if (parts.length >= 2) {
          const art = parts[0].trim();
          let trk = parts[1].replace(/[«»"]/g, '').replace(/\[\d{2}\.\d{2}\.\d{4}\]/g, '').trim();
          if (art.length > 1 && trk.length > 1 && (art.length + trk.length < 75)) {
            drops.push({
              artist: art,
              title: trk,
              type: currentType
            });
          }
        }
      }
    }
  }
  if (item.json.artist && item.json.title) {
    drops.push({
      artist: item.json.artist,
      title: item.json.title,
      type: item.json.type || 'album'
    });
  }
}

const dedupMap = {};
for (const d of drops) {
  const artClean = d.artist.trim();
  const trkClean = d.title.replace(/\s*-\s*(single|ep|album)$/i, '').trim();
  const artKey = artClean.toLowerCase().replace(/[^a-z0-9а-я]/g, '');
  const trkKey = trkClean.toLowerCase().replace(/[^a-z0-9а-я]/g, '');
  const key = `${artKey}_${trkKey}`;
  if (!dedupMap[key]) {
    const searchQ = encodeURIComponent(`${artClean} ${trkClean}`);
    dedupMap[key] = {
      artist: artClean,
      title: trkClean,
      type: d.type || 'single',
      url: `https://open.spotify.com/search/${searchQ}`
    };
  }
}

const uniqueDrops = Object.values(dedupMap);
const favAlbums = [];
const favSingles = [];
const generalAlbums = [];
const generalSingles = [];

for (const drop of uniqueDrops) {
  const artLower = drop.artist.toLowerCase();
  const tokens = artLower.split(/[,&;]|\bfeat\b|\bft\b|\bwith\b/).map(t => t.trim()).filter(t => t.length > 1);
  let isFav = false;
  for (const token of tokens) {
    for (const fav of favArtists) {
      if (fav === token || (fav.length > 3 && token.includes(fav))) {
        isFav = true;
        break;
      }
    }
    if (isFav) break;
  }
  if (isFav) {
    if (drop.type === 'album') favAlbums.push(drop);
    else favSingles.push(drop);
  } else {
    if (drop.type === 'album') generalAlbums.push(drop);
    else generalSingles.push(drop);
  }
}

let msg = '🔥 *ПЯТНИЧНЫЙ МУЗЫКАЛЬНЫЙ РАДАР РЕЛИЗОВ* 🔥\n\n';
if (favAlbums.length > 0 || favSingles.length > 0) {
  msg += '🎧 *Твои любимые артисты*\n\n';
  if (favAlbums.length > 0) {
    msg += '💿 *Альбомы & EP:*\n';
    for (const item of favAlbums) msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
    msg += '\n';
  }
  if (favSingles.length > 0) {
    msg += '🎤 *Синглы:*\n';
    for (const item of favSingles) msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
    msg += '\n';
  }
  msg += '\n';
}

if (generalAlbums.length > 0 || generalSingles.length > 0) {
  msg += '⚡️ *Горячие новинки недели (РФ и Запад)*\n\n';
  if (generalAlbums.length > 0) {
    msg += '💿 *Альбомы & EP:*\n';
    for (const item of generalAlbums) msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
    msg += '\n';
  }
  if (generalSingles.length > 0) {
    msg += '🎤 *Синглы:*\n';
    for (const item of generalSingles) msg += `• [${item.artist} — ${item.title}](${item.url})\n`;
    msg += '\n';
  }
  msg += '\n';
}
msg += 'Нажмите на любой релиз, чтобы открыть его в Spotify! 🎧✨';

return [{ json: { message: msg } }];
